sql:
SELECT COUNT(employee_id) AS num_employees
FROM num_companies_worked
WHERE num_companies > 1;

SELECT e.employee_id, t.total_years
FROM employees e
JOIN total_working_years t ON e.employee_id = t.employee_id;

SELECT total_years
  FROM total_working_years
  ORDER BY total_years DESC;

SELECT employee_id, total_years
FROM total_working_years
ORDER BY total_years DESC;

SELECT employee_id, total_years
FROM total_working_years
WHERE employee_id = 1;

SELECT education_id AS education_level_id, education_field_id AS field_of_study_id, graduation_date, gpa, degree_earned
FROM employee_education
WHERE employee_id = 1;

external_knowledge:
- "Educational backgrounds" refers to the level of education, field of study, graduation date, GPA, and degree earned; 
- "Total earnings" are calculated based on the average salary for each job multiplied by the duration of the job in years. 
- "Most recent benefit" refers to the benefit with the latest effective date for each employee.

